const body = $input.first().json.body || $input.first().json;

// Template type determines which PDF layout to generate
const templateType = body.template || 'invoice';

// Build HTML based on template type
let htmlContent = '';
const now = new Date();
const dateStr = now.toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });

if (templateType === 'invoice') {
  const items = body.items || [{ description: 'Service', quantity: 1, price: 100 }];
  const subtotal = items.reduce((s, i) => s + (i.quantity * i.price), 0);
  const tax = subtotal * (body.taxRate || 0.1);
  const total = subtotal + tax;

  const itemRows = items.map(item =>
    `<tr>
      <td style="padding:10px; border-bottom:1px solid #e5e7eb;">${item.description}</td>
      <td style="padding:10px; border-bottom:1px solid #e5e7eb; text-align:center;">${item.quantity}</td>
      <td style="padding:10px; border-bottom:1px solid #e5e7eb; text-align:right;">$${parseFloat(item.price).toFixed(2)}</td>
      <td style="padding:10px; border-bottom:1px solid #e5e7eb; text-align:right;">$${(item.quantity * item.price).toFixed(2)}</td>
    </tr>`
  ).join('');

  htmlContent = `<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Invoice ${body.invoiceNumber || 'INV-001'}</title></head>
<body style="font-family: Arial, sans-serif; margin: 40px; color: #333;">
  <div style="display:flex; justify-content:space-between; align-items:start; margin-bottom:40px;">
    <div>
      <h1 style="color:#4f46e5; margin:0;">INVOICE</h1>
      <p style="color:#6b7280; margin:4px 0;">Invoice #: ${body.invoiceNumber || 'INV-001'}</p>
      <p style="color:#6b7280; margin:4px 0;">Date: ${dateStr}</p>
      <p style="color:#6b7280; margin:4px 0;">Due: ${body.dueDate || 'Net 30'}</p>
    </div>
    <div style="text-align:right;">
      <h2 style="margin:0; color:#1a1a2e;">${body.companyName || 'Your Company'}</h2>
      <p style="margin:4px 0; color:#6b7280;">${body.companyAddress || ''}</p>
      <p style="margin:4px 0; color:#6b7280;">${body.companyEmail || ''}</p>
    </div>
  </div>
  <div style="background:#f9fafb; padding:16px; border-radius:8px; margin-bottom:24px;">
    <h3 style="margin:0 0 8px;">Bill To:</h3>
    <p style="margin:2px 0;">${body.clientName || ''}</p>
    <p style="margin:2px 0;">${body.clientAddress || ''}</p>
    <p style="margin:2px 0;">${body.clientEmail || ''}</p>
  </div>
  <table style="width:100%; border-collapse:collapse;">
    <thead><tr style="background:#4f46e5; color:white;">
      <th style="padding:10px; text-align:left;">Description</th>
      <th style="padding:10px; text-align:center;">Qty</th>
      <th style="padding:10px; text-align:right;">Rate</th>
      <th style="padding:10px; text-align:right;">Amount</th>
    </tr></thead>
    <tbody>${itemRows}</tbody>
  </table>
  <div style="text-align:right; margin-top:16px;">
    <p>Subtotal: <strong>$${subtotal.toFixed(2)}</strong></p>
    <p>Tax (${((body.taxRate || 0.1)*100).toFixed(0)}%): <strong>$${tax.toFixed(2)}</strong></p>
    <p style="font-size:1.5em; color:#4f46e5;">Total: <strong>$${total.toFixed(2)}</strong></p>
  </div>
  ${body.notes ? `<div style="margin-top:24px; padding:16px; background:#fffbeb; border-radius:8px;"><strong>Notes:</strong><br>${body.notes}</div>` : ''}
</body></html>`;

  return [{ json: { htmlContent, templateType, recipientEmail: body.clientEmail || body.email, recipientName: body.clientName || 'Client', subject: `Invoice ${body.invoiceNumber || 'INV-001'} from ${body.companyName || 'Us'}`, filename: `Invoice-${body.invoiceNumber || 'INV-001'}.pdf` } }];
}

// Default: simple report template
htmlContent = `<!DOCTYPE html><html><body style="font-family:Arial,sans-serif; margin:40px;">
<h1>${body.title || 'Report'}</h1><p>Generated: ${dateStr}</p>
<div>${body.content || 'No content provided.'}</div>
</body></html>`;

return [{ json: { htmlContent, templateType, recipientEmail: body.email, recipientName: body.name || 'Recipient', subject: body.emailSubject || 'Your PDF is ready', filename: 'document.pdf' } }];
